import React from 'react';
import { ShieldExclamationIcon } from '@heroicons/react/24/solid';

const SOSButton = () => {
  const handleSOS = () => alert("SOS Alert Sent!");

  return (
    <button
      onClick={handleSOS}
      style={{
        position: 'fixed', bottom: '24px', right: '24px', zIndex: 100,
        width: '56px', height: '56px', borderRadius: '50%', backgroundColor: '#dc2626',
        border: 'none', cursor: 'pointer', boxShadow: '0 4px 15px rgba(220, 38, 38, 0.4)',
        display: 'flex', alignItems: 'center', justifyContent: 'center'
      }}
    >
      <ShieldExclamationIcon style={{ height: '28px', width: '28px', color: '#fff' }} />
    </button>
  );
};

export default SOSButton;
